func solve(sx: Int64, sy: Int64, x: Int64, y: Int64) -> Int64 {
    var tx = x
    var ty = y
    var steps: Int64 = 0

    while tx > sx && ty > sy {
        if tx > ty {
            let moved = (tx - sx) / ty
            if moved > 0 {
                let n = moved > (tx / ty) ? (tx / ty) : moved
                tx -= n * ty
                steps += n
            } else {
                tx -= ty
                steps += 1
            }
        } else {
            let moved = (ty - sy) / tx
            if moved > 0 {
                let n = moved > (ty / tx) ? (ty / tx) : moved
                ty -= n * tx
                steps += n
            } else {
                ty -= tx
                steps += 1
            }
        }
    }

    if tx == sx && ty == sy {
        return steps
    } else if tx == sx {
        if ty >= sy && (ty - sy) % sx == 0 {
            return steps + (ty - sy) / sx
        } else {
            return -1
        }
    } else if ty == sy {
        if tx >= sx && (tx - sx) % sy == 0 {
            return steps + (tx - sx) / sy
        } else {
            return -1
        }
    } else {
        return -1
    }
}
